try {
    var params = JSON.parse(value),
        req = new HttpRequest(),
        fields = {},
        resp = '';

    // Rootly severity mapping (can be customized in Rootly UI)
    var severityMapping = [
        'info',    // Not classified
        'info',    // Information
        'low',     // Warning
        'medium',  // Average
        'high',    // High
        'critical' // Disaster
    ];

    if (!severityMapping[params.severity]) {
        params.severity = '0';
    }

    if (typeof params.HTTPProxy === 'string' && params.HTTPProxy.trim() !== '') {
        req.setProxy(params.HTTPProxy);
    }

    // Validation - check webhook_url is provided
    if (typeof params.webhook_url !== 'string' || params.webhook_url.trim() === '') {
        throw 'webhook_url parameter is required. Set this to your Rootly webhook URL from Alert Sources.';
    }

    // Validation - check token is provided
    if (typeof params.token !== 'string' || params.token.trim() === '') {
        throw 'token parameter is required. Set this to your Rootly Bearer token from Alert Sources.';
    }

    // Validation
    if (isNaN(parseInt(params.eventid)) || params.eventid < 1) {
        throw 'incorrect value for variable "eventid". The value must be a positive number.';
    }
    if (params.eventname.length < 1) {
        throw 'incorrect value for variable "eventname". The value must be a non-empty string.';
    }
    if (isNaN(parseInt(params.severity)) || (params.severity < 0 && params.severity > 5)) {
        throw 'incorrect value for variable "severity". The value must be a number 0..5.';
    }

    if ([0, 1, 2, 3].indexOf(parseInt(params.event_source)) === -1) {
        throw 'Incorrect "event_source" parameter given: "' + params.event_source + '".\nMust be 0-3.';
    }

    // Check {EVENT.VALUE} for trigger-based and internal events
    if (params.eventvalue !== '0' && params.eventvalue !== '1'
        && (params.event_source === '0' || params.event_source === '3')) {
        throw 'Incorrect "eventvalue" parameter given: "' + params.eventvalue + '".\nMust be 0 or 1.';
    }

    if (params.event_source === '0') {
        if (params.hostname.length < 1) {
            throw 'incorrect value for variable "hostname". The value must be a non-empty string.';
        }
        if (isNaN(parseInt(params.triggerid)) || params.triggerid < 1) {
            throw 'incorrect value for variable "triggerid". The value must be a positive number.';
        }
        if (params.eventack != 'Yes' && params.eventack != 'No') {
            throw 'incorrect value for variable "eventack". The value must be Yes or No.';
        }
        if (isNaN(parseInt(params.eventupdate)) || (params.eventupdate < 0 || params.eventupdate > 1)) {
            throw 'incorrect value for variable "eventupdate". The value must be 0 or 1.';
        }
    }

    // Set headers for Rootly
    req.addHeader('Content-Type: application/json');
    req.addHeader('Authorization: Bearer ' + params.token);

    // Build Rootly webhook payload - flat structure for easy Liquid access
    fields.alert_id = params.eventid;
    fields.alert_name = params.eventname;
    fields.severity = severityMapping[params.severity];
    fields.original_source = 'Zabbix';
    fields.zabbix_url = params.url;

    // Determine alert state for auto-resolve functionality
    if (params.eventvalue == 0) {
        fields.state = 'resolved';
    } else {
        fields.state = 'firing';
    }

    // Add event-specific details
    if (params.event_source === '0') {
        fields.host = params.hostname;
        fields.host_ip = params.hostip;
        fields.event_date = params.eventdate;
        fields.event_time = params.eventtime;
        fields.trigger_id = params.triggerid;
        fields.trigger_description = params.triggerdesc;
        fields.trigger_opdata = params.triggeropdata;
        fields.event_tags = params.eventtags;
        fields.acknowledged = params.eventack;

        // Create direct event URL for easy linking in Rootly
        fields.event_url = params.url + '/tr_events.php?triggerid=' + params.triggerid + '&eventid=' + params.eventid;

    } else if (params.event_source === '1') {
        fields.source_type = 'Discovery';
        fields.alert_message = params.alert_message;
    } else {
        fields.alert_message = params.alert_message;
    }

    Zabbix.log(4, '[Rootly Webhook] Sending request: ' + JSON.stringify(fields));

    // Send to Rootly webhook URL
    resp = req.post(params.webhook_url, JSON.stringify(fields));

    Zabbix.log(4, '[Rootly Webhook] Receiving response: ' + resp);

    // Rootly returns 200/202 for successful webhook ingestion
    if (req.getStatus() < 200 || req.getStatus() >= 300) {
        try {
            resp = JSON.parse(resp);
            if (typeof resp.error === 'string') {
                throw resp.error;
            }
        } catch (parseError) {
            throw 'HTTP request failed with status: ' + req.getStatus() + ', response: ' + resp;
        }
    }

    return 'OK';
}
catch (error) {
    Zabbix.log(3, '[Rootly Webhook] Notification failed: ' + error);
    throw 'Rootly notification failed: ' + error;
}

